mapper.update:
UPDATE pr_house
SET in_temperature = #{inTemperature},
    out_temperature = #{outTemperature}

    ,actual_open = #{actualOpen}

WHERE id = #{houseId}

mapper.select:
SELECT *
FROM pr_heat_valve_archive
WHERE org_id = #{orgId}
  AND is_changed = 0
  AND valve_status = #{valveStatus}
